  1	import { useState, FC, useCallback, useMemo, useRef, useEffect, memo } from 'react';
  2	
  3	import { RESTApi } from '@API/REST.api';
  4	import { I18nNamespace } from '@config/config';
  5	import { createAccessGrantRequest } from '@core/utils/createCRD';
  6	import useValidatedInput from '@hooks/useValidation';
  7	import { AccessGrantCrdParams, AccessGrantParams } from '@interfaces/CRD_AccessGrant';
  8	import { HTTPError } from '@interfaces/REST.interfaces';
  9	import {
 10	  Button,
 11	  Alert,
 12	  Wizard,
 13	  WizardFooterWrapper,
 14	  WizardHeader,
 15	  WizardStep,
 16	  PageSection,
 17	  PageSectionVariants
 18	} from '@patternfly/react-core';
 19	import { useMutation } from '@tanstack/react-query';
 20	import { useTranslation } from 'react-i18next';
 21	
 22	import { DownloadGrant } from './DownloadGrant';
 23	import { FormPage } from './FormPage';
 24	
 25	const DEFAULT_EXPIRATION = 15;
 26	const DEFAULT_CLAIMS = 1;
 27	
 28	enum ValidForUnit {
 29	  Minutes = 'm',
 30	  Hours = 'h'
 31	}
 32	
 33	const ButtonName: string[] = ['Create', 'Done'];
 34	
 35	const GrantForm: FC<{ onSubmit?: () => void; onCancel?: () => void }> = memo(({ onCancel }) => {
 36	  const { t } = useTranslation(I18nNamespace);
 37	
 38	  const [name, setName] = useState('');
 39	  const [step, setStep] = useState(1);
 40	
 41	  const { validated: validationError, validateInput: setValidationError } = useValidatedInput();
 42	
 43	  const validForRef = useRef<number | undefined>(DEFAULT_EXPIRATION);
 44	  const validForUnitRef = useRef<ValidForUnit>(ValidForUnit.Minutes);
 45	  const claimsRef = useRef<number | undefined>(DEFAULT_CLAIMS);
 46	  const codeRef = useRef<string>('');
 47	
 48	  const mutationCreate = useMutation({
 49	    mutationFn: (data: AccessGrantParams) => RESTApi.createGrant(data),
 50	    onError: (data: HTTPError) => {
 51	      setValidationError(data.descriptionMessage);
 52	    },
 53	    onSuccess: () => {
 54	      setValidationError(undefined);
 55	      setStep(step + 1);
 56	    }
 57	  });
 58	
 59	  const handleSubmit = useCallback(() => {
 60	    const data: AccessGrantCrdParams = createAccessGrantRequest({
 61	      metadata: {
 62	        name
 63	      },
 64	      spec: {
 65	        expirationWindow: `${validForRef.current || DEFAULT_EXPIRATION}${validForUnitRef.current}`,
 66	        redemptionsAllowed: claimsRef.current || DEFAULT_CLAIMS,
 67	        code: codeRef.current
 68	      }
 69	    });
 70	
 71	    mutationCreate.mutate(createAccessGrantRequest(data));
 72	  }, [mutationCreate, name]);
 73	
 74	  const handleNextStep = useCallback(() => {
 75	    if (step === 1) {
 76	      handleSubmit();
 77	    }
 78	
 79	    if (step === 2) {
 80	      onCancel?.();
 81	    }
 82	  }, [handleSubmit, onCancel, step]);
 83	
 84	  const handleKeyPress = useCallback(
 85	    (event: KeyboardEvent) => {
 86	      if (event.key === 'Enter') {
 87	        event.preventDefault();
 88	        handleNextStep();
 89	      }
 90	    },
 91	    [handleNextStep]
 92	  );
 93	
 94	  useEffect(() => {
 95	    window.addEventListener('keydown', handleKeyPress);
 96	
 97	    return () => {
 98	      window.removeEventListener('keydown', handleKeyPress); // Cleanup listener on unmount
 99	    };
100	  }, [handleKeyPress]);
101	
102	  const steps = useMemo(
103	    () => [
104	      <WizardStep name={t('Configuration')} id="1-step" key="1-step">
105	        <FormPage
106	          name={name}
107	          onSetName={(value: string) => setName(value)}
108	          onSetValidFor={(value: number | undefined) => (validForRef.current = value)}
109	          onSetValidForUnit={(value: ValidForUnit) => (validForUnitRef.current = value)}
110	          onSetClaims={(value: number | undefined) => (claimsRef.current = value)}
111	          onSetCode={(value: string) => (codeRef.current = value)}
112	        />
113	      </WizardStep>,
114	      <WizardStep name={t('Create token')} id="2-step" key="2-step">
115	        <DownloadGrant name={name} />
116	      </WizardStep>
117	    ],
118	    [name, t]
119	  );
120	
121	  return (
122	    <Wizard
123	      key={step}
124	      startIndex={step}
125	      title=""
126	      header={
127	        <WizardHeader
128	          title={t('Create token')}
129	          description={t('A token indicating authorization to generate a link.')}
130	          isCloseHidden={true}
131	        />
132	      }
133	      footer={
134	        <>
135	          {validationError && step === 1 && (
136	            <PageSection variant={PageSectionVariants.light}>
137	              <Alert variant="danger" title={t('An error occurred')} aria-live="polite" isInline>
138	                {validationError}
139	              </Alert>
140	            </PageSection>
141	          )}
142	
143	          <WizardFooterWrapper>
144	            <Button onClick={handleNextStep}>{t(ButtonName[step - 1])}</Button>
145	            {step === 1 && (
146	              <Button variant="link" onClick={onCancel}>
147	                {t('Cancel')}
148	              </Button>
149	            )}
150	          </WizardFooterWrapper>
151	        </>
152	      }
153	    >
154	      {...steps}
155	    </Wizard>
156	  );
157	});
158	
159	export default GrantForm;

